def _dashboard_refresh_epic_work_item_row(
    norm: dict,
    issue_type_label: str,
    parent_key: str,
    epic_key: str,
    total_hours: float = 0.0,
    ipp_row: dict | None = None,
) -> list:
    """Build a work_items row (28 elements in WORK_ITEMS_COLS order) from normalized PVD issue."""
    ipp = ipp_row or {}
    est_hours = norm.get("estimate_hours")
    try:
        est_hours = float(est_hours) if est_hours is not None else None
    except (TypeError, ValueError):
        est_hours = None
    orig_est = str(est_hours) + "h" if est_hours is not None and est_hours > 0 else ""
    key = _to_text(norm.get("issue_key")).upper()
    parent_jira_url = f"{BASE_URL}/browse/{parent_key}" if parent_key else ""
    return [
        _to_text(norm.get("project_key")) or "",
        key,
        key,
        issue_type_label,
        _to_text(norm.get("issue_type_name")) or issue_type_label,
        None,
        _to_text(norm.get("summary")) or "",
        _to_text(norm.get("status")) or "",
        _to_text(norm.get("planned_start")) or None,
        _to_text(norm.get("planned_due")) or None,
        None,
        None,
        orig_est,
        est_hours,
        _to_text(norm.get("assignee")) or "",
        total_hours,
        None,
        parent_key or None,
        parent_key or None,
        parent_jira_url or None,
        _to_text(norm.get("jira_url")) or "",
        ipp.get("latest_ipp_meeting", ""),
        ipp.get("jira_ipp_rmi_dates_altered", ""),
        ipp.get("ipp_actual_date", ""),
        ipp.get("ipp_remarks", ""),
        ipp.get("ipp_actual_date_matches_jira_end_date", ""),
        None,
        None,
    ]


def _dashboard_refresh_epic_impl(
    *,
    capacity_paths: dict,
    epic_key: str,
    run_id: str = "",
) -> dict:
    return _dashboard_build_epic_payload_from_db(
        settings_db_path=Path(capacity_paths["db_path"]),
        epic_key=epic_key,
        run_id=run_id,
    )


def _dashboard_apply_epic_planner_fields(epic_item: dict[str, object], planner_lookup: dict[str, dict[str, object]]) -> None:
    planner = planner_lookup.get(dash_normalize_issue_key(epic_item.get("issue_key"))) or {}
    has_planner_entry = bool(planner)
    planner_start = _to_text(planner.get("planner_start_date"))
    planner_end = _to_text(planner.get("planner_end_date"))
    planner_hours = planner.get("planner_planned_hours")
    planner_complete = bool(planner_start and planner_end and planner_hours is not None)

    jira_start = _to_text(epic_item.get("jira_start_date"))
    jira_end = _to_text(epic_item.get("jira_end_date"))
    jira_hours = float(epic_item.get("planned_hours_numeric") or 0.0)
    jira_hours_available = _to_text(epic_item.get("original_estimate")) != ""

    dates_match = "N/A"
    if planner_complete and jira_start and jira_end:
        dates_match = "Yes" if planner_start == jira_start and planner_end == jira_end else "No"

    hours_match = "N/A"
    if planner_complete and jira_hours_available:
        hours_match = "Yes" if abs(float(planner_hours) - jira_hours) < 0.01 else "No"

    if not has_planner_entry:
        planner_status = "No Planner Entry"
    elif not planner_complete:
        planner_status = "Incomplete"
    elif dates_match == "Yes" and hours_match == "Yes":
        planner_status = "Matched"
    else:
        planner_status = "Mismatch"

    epic_item["planner_has_entry"] = has_planner_entry
    epic_item["planner_planned_start_date"] = planner_start
    epic_item["planner_planned_end_date"] = planner_end
    epic_item["planner_planned_hours"] = planner_hours
    epic_item["planner_dates_match"] = dates_match
    epic_item["planner_hours_match"] = hours_match
    epic_item["planner_validation_status"] = planner_status


def _dashboard_build_epic_payload_from_db(
    *,
    settings_db_path: Path,
    epic_key: str,
    run_id: str = "",
) -> dict[str, object]:
    target_epic_key = _to_text(epic_key).upper()
    effective_run_id = _to_text(run_id) or _canonical_last_success_run_id(settings_db_path)
    if not effective_run_id:
        raise _CanonicalMissingError("No successful canonical refresh found. Run the canonical refresh first.")

    planner_lookup = dash_load_planner_epic_plan_by_key(settings_db_path)
    planner_story_lookup = dash_load_planner_story_dates_by_key(settings_db_path)
    ipp_meta_lookup = dash_load_epics_management_dashboard_meta(settings_db_path)
    risk_settings = dash_load_risk_settings(settings_db_path)
    today_utc = datetime.now(timezone.utc).date()

    with sqlite3.connect(settings_db_path) as conn:
        conn.row_factory = sqlite3.Row
        issue_rows = [
            dict(row)
            for row in conn.execute(
                """
                SELECT issue_key, project_key, issue_type, summary, status, assignee,
                       start_date, due_date, original_estimate_hours, parent_issue_key,
                       story_key, epic_key
                FROM canonical_issues
                WHERE run_id = ?
                  AND (issue_key = ? OR epic_key = ?)
                ORDER BY issue_key
                """,
                (effective_run_id, target_epic_key, target_epic_key),
            ).fetchall()
        ]
        worklog_rows = [
            dict(row)
            for row in conn.execute(
                """
                SELECT issue_key, started_utc, started_date, hours_logged
                FROM canonical_worklogs
                WHERE run_id = ?
                  AND issue_key IN (
                      SELECT issue_key
                      FROM canonical_issues
                      WHERE run_id = ?
                        AND (issue_key = ? OR epic_key = ?)
                  )
                ORDER BY started_utc ASC, issue_key ASC
                """,
                (effective_run_id, effective_run_id, target_epic_key, target_epic_key),
            ).fetchall()
        ]

    if not issue_rows:
        raise LookupError(f"Epic '{target_epic_key}' not found in canonical hierarchy.")

    worklogs_by_issue: dict[str, list[dict[str, object]]] = defaultdict(list)
    for row in worklog_rows:
        worklogs_by_issue[_to_text(row.get("issue_key")).upper()].append(row)

    epic_item: dict[str, object] | None = None
    stories_map: dict[str, dict[str, object]] = {}
    subtasks_map: dict[str, dict[str, object]] = {}
    bug_subtasks_map: dict[str, dict[str, object]] = {}

    for row in issue_rows:
        issue_key = _to_text(row.get("issue_key")).upper()
        issue_type_name = _to_text(row.get("issue_type"))
        total_hours = round(
            sum(float(item.get("hours_logged") or 0.0) for item in worklogs_by_issue.get(issue_key, [])),
            2,
        )
        est_hours = float(row.get("original_estimate_hours") or 0.0)
        dashboard_row = {
            "issue_key": issue_key,
            "jira_issue_type": issue_type_name,
            "parent_issue_key": _to_text(row.get("parent_issue_key")).upper(),
            "summary": _to_text(row.get("summary")),
            "assignee": _to_text(row.get("assignee")) or "Unassigned",
            "project_key": _to_text(row.get("project_key")).upper(),
            "jira_url": f"{BASE_URL}/browse/{issue_key}",
            "start_date": _to_text(row.get("start_date")),
            "end_date": _to_text(row.get("due_date")),
            "actual_start_date": "",
            "actual_end_date": "",
            "original_estimate": (f"{round(est_hours, 2):g}h" if est_hours > 0 else ""),
            "total_hours_logged": total_hours,
            "status": _to_text(row.get("status")),
        }
        item_kind = "Epic" if _canonical_is_epic_type(issue_type_name) else ("Story" if "story" in issue_type_name.lower() else issue_type_name or "Sub-task")
        item = dash_build_item(dashboard_row, item_kind)
        if _canonical_is_epic_type(issue_type_name):
            item["epic_key"] = issue_key
            item["epic_key_legacy"] = issue_key
            item["epic_status"] = item.get("status", "")
            epic_item = item
        elif _canonical_is_subtask_type(issue_type_name):
            item["story_key"] = _to_text(row.get("story_key")).upper()
            item["epic_key"] = _to_text(row.get("epic_key")).upper()
            if "bug" in issue_type_name.lower():
                bug_subtasks_map[issue_key] = item
            else:
                subtasks_map[issue_key] = item
        else:
            item["epic_key"] = _to_text(row.get("epic_key")).upper()
            planner_story = planner_story_lookup.get(dash_normalize_issue_key(issue_key)) or {}
            item["planner_story_start_date"] = _to_text(planner_story.get("start_date"))
            item["planner_story_end_date"] = _to_text(planner_story.get("due_date"))
            item["planner_story_planned_hours"] = planner_story.get("estimate_hours")
            stories_map[issue_key] = item

    if not epic_item:
        raise LookupError(f"Epic '{target_epic_key}' not found in canonical hierarchy.")

    epic_item["subtask_hours_logged_total"] = round(
        sum(float(item.get("total_hours_logged") or 0.0) for item in list(subtasks_map.values()) + list(bug_subtasks_map.values())),
        2,
    )
    _dashboard_apply_epic_planner_fields(epic_item, planner_lookup)
    dash_apply_epics_management_ipp_fields(
        epic_item,
        target_epic_key,
        ipp_meta_lookup,
        jira_start_date=epic_item.get("jira_start_date"),
        jira_end_date=epic_item.get("jira_end_date"),
    )

    for story_item in stories_map.values():
        dash_apply_epics_management_ipp_fields(
            story_item,
            target_epic_key,
            ipp_meta_lookup,
            jira_start_date=epic_item.get("jira_start_date"),
            jira_end_date=epic_item.get("jira_end_date"),
        )
    for subtask_item in list(subtasks_map.values()) + list(bug_subtasks_map.values()):
        dash_apply_epics_management_ipp_fields(
            subtask_item,
            target_epic_key,
            ipp_meta_lookup,
            jira_start_date=epic_item.get("jira_start_date"),
            jira_end_date=epic_item.get("jira_end_date"),
        )

    for item in list(subtasks_map.values()) + list(bug_subtasks_map.values()):
        dash_compute_self_risk(item, today_utc, risk_settings)
    for item in stories_map.values():
        dash_compute_self_risk(item, today_utc, risk_settings)
    dash_compute_self_risk(epic_item, today_utc, risk_settings)
    dash_apply_risk_rollup({target_epic_key: epic_item}, stories_map, subtasks_map, bug_subtasks_map, risk_settings)

    return {
        "epic": epic_item,
        "stories": sorted(stories_map.values(), key=lambda item: _to_text(item.get("issue_key")).upper()),
        "subtasks": sorted(subtasks_map.values(), key=lambda item: _to_text(item.get("issue_key")).upper()),
        "bug_subtasks": sorted(bug_subtasks_map.values(), key=lambda item: _to_text(item.get("issue_key")).upper()),
    }


def _settings_top_nav_html(active_route: str) -> str:
    _ = active_route
    # Admin page-to-page links are intentionally removed from headers.
    # Navigation is handled by the shared left navigation.
    return ""


def _base_page_catalog() -> list[dict[str, object]]:
    items = STATIC_REPORT_NAV_ITEMS + STATIC_ADMIN_NAV_ITEMS
    out: list[dict[str, object]] = []
    for item in items:
        out.append(
            {
                "page_key": _to_text(item.get("page_key")),
                "title": _to_text(item.get("title")),
                "default_title": _to_text(item.get("title")),
                "display_name": "",
                "route_or_file": _to_text(item.get("path") or item.get("file") or item.get("href")),
                "href": _to_text(item.get("href")),
                "icon": _to_text(item.get("icon")),
                "page_type": _to_text(item.get("page_type")),
                "default_nav_order": int(item.get("default_nav_order") or 0),
                "title_editable": _to_text(item.get("page_type")) == "report",
            }
        )
    return out


def _page_catalog(db_path: Path | None = None) -> list[dict[str, object]]:
    out = _base_page_catalog()
    if not db_path:
        return out
    overrides = _load_page_display_name_overrides(db_path)
    for item in out:
        page_key = _to_text(item.get("page_key"))
        override = overrides.get(page_key, "")
        item["display_name"] = override
        item["title"] = override or _to_text(item.get("default_title"))
    return out


def _normalize_page_category_name(value: object) -> str:
    name = _to_text(value)
    if not name:
        raise ValueError("Category name is required.")
    return name


def _canonical_page_key(value: object) -> str:
    page_key = _to_text(value)
    if page_key == LEGACY_PVD_PAGE_KEY:
        return CANONICAL_PVD_PAGE_KEY
    return page_key


def _normalize_google_icon_name(value: object) -> str:
    icon_name = _to_text(value).lower()
    if not icon_name:
        return "folder"
    if not re.match(r"^[a-z0-9_]+$", icon_name):
        raise ValueError("icon_name must contain only lowercase letters, numbers, and underscores.")
    return icon_name


def _normalize_page_category_payload(payload: object, require_name: bool = True) -> dict[str, object]:
    raw = payload if isinstance(payload, dict) else {}
    name = _to_text(raw.get("name"))
    if require_name:
        name = _normalize_page_category_name(name)
    display_order_raw = raw.get("display_order", 100)
    try:
        display_order = int(display_order_raw)
    except (TypeError, ValueError):
        raise ValueError("display_order must be an integer.")
    return {
        "id": int(raw.get("id") or 0),
        "name": name,
        "icon_name": _normalize_google_icon_name(raw.get("icon_name")),
        "display_in_navigation": 1 if bool(raw.get("display_in_navigation", True)) else 0,
        "display_order": display_order,
        "is_active": 1 if bool(raw.get("is_active", True)) else 0,
    }


def _normalize_page_assignment_payload(payload: object, valid_page_keys: set[str], valid_category_ids: set[int]) -> dict[str, object]:
    raw = payload if isinstance(payload, dict) else {}
    page_key_raw = _to_text(raw.get("page_key"))
    page_key = _canonical_page_key(page_key_raw)
    if not page_key:
        raise ValueError("page_key is required for assignments.")
    if page_key not in valid_page_keys:
        # Backward/forward compatibility for mixed frontend/backend versions.
        if page_key == CANONICAL_PVD_PAGE_KEY and LEGACY_PVD_PAGE_KEY in valid_page_keys:
            page_key = LEGACY_PVD_PAGE_KEY
        elif page_key == LEGACY_PVD_PAGE_KEY and CANONICAL_PVD_PAGE_KEY in valid_page_keys:
            page_key = CANONICAL_PVD_PAGE_KEY
    if page_key not in valid_page_keys:
        raise ValueError(f"Unknown page_key: {page_key}")
    page_type = _to_text(raw.get("page_type")).lower()
    if page_type not in {"report", "configuration"}:
        raise ValueError("page_type must be report or configuration.")
    try:
        category_id = int(raw.get("category_id"))
    except (TypeError, ValueError):
        raise ValueError("category_id must be an integer.")
    if category_id not in valid_category_ids:
        raise ValueError(f"Unknown category_id: {category_id}")
    return {
        "page_key": page_key,
        "page_type": page_type,
        "category_id": category_id,
    }


def _normalize_page_display_name_payload(payload: object, valid_pages_by_key: dict[str, dict[str, object]]) -> dict[str, str]:
    raw = payload if isinstance(payload, dict) else {}
    page_key_raw = _to_text(raw.get("page_key"))
    page_key = _canonical_page_key(page_key_raw)
    if not page_key:
        raise ValueError("page_key is required for page display names.")
    page = valid_pages_by_key.get(page_key)
    if not page:
        raise ValueError(f"Unknown page_key for display name override: {page_key}")
    if _to_text(page.get("page_type")) != "report":
        raise ValueError(f"Display name overrides are only supported for report pages: {page_key}")
    return {
        "page_key": page_key,
        "display_name": _to_text(raw.get("display_name")),
    }


def _init_page_categories_db(db_path: Path) -> None:
    db_path.parent.mkdir(parents=True, exist_ok=True)
    conn = sqlite3.connect(db_path)
    try:
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS page_categories (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL COLLATE NOCASE UNIQUE,
                icon_name TEXT NOT NULL DEFAULT 'folder',
                display_in_navigation INTEGER NOT NULL DEFAULT 1,
                display_order INTEGER NOT NULL DEFAULT 100,
                is_active INTEGER NOT NULL DEFAULT 1,
                created_at_utc TEXT NOT NULL,
                updated_at_utc TEXT NOT NULL
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS page_category_assignments (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                page_key TEXT NOT NULL,
                page_type TEXT NOT NULL,
                category_id INTEGER NOT NULL,
                created_at_utc TEXT NOT NULL,
                updated_at_utc TEXT NOT NULL,
                UNIQUE(page_key, category_id),
                FOREIGN KEY(category_id) REFERENCES page_categories(id) ON DELETE CASCADE
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS page_display_name_overrides (
                page_key TEXT PRIMARY KEY,
                display_name TEXT NOT NULL,
                updated_at_utc TEXT NOT NULL
            )
            """
        )
        columns = conn.execute("PRAGMA table_info(page_categories)").fetchall()
        column_names = {str(row[1]) for row in columns}
        if "icon_name" not in column_names:
            conn.execute("ALTER TABLE page_categories ADD COLUMN icon_name TEXT NOT NULL DEFAULT 'folder'")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_page_category_assignments_page_key ON page_category_assignments(page_key)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_page_category_assignments_category ON page_category_assignments(category_id)")
        conn.commit()
    finally:
        conn.close()


def _load_page_display_name_overrides(db_path: Path) -> dict[str, str]:
    _init_page_categories_db(db_path)
    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    try:
        rows = conn.execute(
            """
            SELECT page_key, display_name
            FROM page_display_name_overrides
            ORDER BY page_key ASC
            """
        ).fetchall()
    finally:
        conn.close()
    overrides: dict[str, str] = {}
    for row in rows:
        page_key = _canonical_page_key(row["page_key"])
        if not page_key:
            continue
        display_name = _to_text(row["display_name"])
        if display_name:
            overrides[page_key] = display_name
    return overrides


def _row_to_page_category(row: sqlite3.Row) -> dict[str, object]:
    return {
        "id": int(row["id"]),
        "name": _to_text(row["name"]),
        "icon_name": _normalize_google_icon_name(row["icon_name"]),
        "display_in_navigation": bool(int(row["display_in_navigation"] or 0)),
        "display_order": int(row["display_order"] or 0),
        "is_active": bool(int(row["is_active"] or 0)),
        "created_at_utc": _to_text(row["created_at_utc"]),
        "updated_at_utc": _to_text(row["updated_at_utc"]),
    }


def _load_page_categories(db_path: Path) -> dict[str, object]:
    _init_page_categories_db(db_path)
    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    try:
        category_rows = conn.execute(
            """
            SELECT id, name, icon_name, display_in_navigation, display_order, is_active, created_at_utc, updated_at_utc
            FROM page_categories
            WHERE is_active = 1
            ORDER BY display_order ASC, lower(name) ASC, id ASC
            """
        ).fetchall()
        assignment_rows = conn.execute(
            """
            SELECT id, page_key, page_type, category_id, created_at_utc, updated_at_utc
            FROM page_category_assignments
            ORDER BY page_type ASC, page_key ASC, category_id ASC
            """
        ).fetchall()
        page_override_rows = conn.execute(
            """
            SELECT page_key, display_name, updated_at_utc
            FROM page_display_name_overrides
            ORDER BY page_key ASC
            """
        ).fetchall()
    finally:
        conn.close()
    categories = [_row_to_page_category(row) for row in category_rows]
    category_ids = {int(item["id"]) for item in categories}
    assignments: list[dict[str, object]] = []
    for row in assignment_rows:
        category_id = int(row["category_id"] or 0)
        if category_id not in category_ids:
            continue
        assignments.append(
            {
                "id": int(row["id"]),
                "page_key": _canonical_page_key(row["page_key"]),
                "page_type": _to_text(row["page_type"]),
                "category_id": category_id,
                "created_at_utc": _to_text(row["created_at_utc"]),
                "updated_at_utc": _to_text(row["updated_at_utc"]),
            }
        )
    page_overrides: list[dict[str, object]] = []
    valid_pages_by_key = {item["page_key"]: item for item in _base_page_catalog()}
    for row in page_override_rows:
        page_key = _canonical_page_key(row["page_key"])
        page = valid_pages_by_key.get(page_key)
        if not page or _to_text(page.get("page_type")) != "report":
            continue
        display_name = _to_text(row["display_name"])
        if not display_name:
            continue
        page_overrides.append(
            {
                "page_key": page_key,
                "display_name": display_name,
                "updated_at_utc": _to_text(row["updated_at_utc"]),
            }
        )
    return {
        "categories": categories,
        "assignments": assignments,
        "page_overrides": page_overrides,
        "page_catalog": _page_catalog(db_path),
        "has_categories": len(categories) > 0,
    }


def _create_page_category(db_path: Path, payload: object) -> dict[str, object]:
    _init_page_categories_db(db_path)
    normalized = _normalize_page_category_payload(payload, require_name=True)
    now = _utc_now_iso()
    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    try:
        cur = conn.execute(
            """
            INSERT INTO page_categories(name, icon_name, display_in_navigation, display_order, is_active, created_at_utc, updated_at_utc)
            VALUES(?, ?, ?, ?, ?, ?, ?)
            """,
            (
                normalized["name"],
                normalized["icon_name"],
                normalized["display_in_navigation"],
                normalized["display_order"],
                normalized["is_active"],
                now,
                now,
            ),
        )
        conn.commit()
        category_id = int(cur.lastrowid or 0)
        row = conn.execute(
            """
            SELECT id, name, icon_name, display_in_navigation, display_order, is_active, created_at_utc, updated_at_utc
            FROM page_categories
            WHERE id = ?
            """,
            (category_id,),
        ).fetchone()
    except sqlite3.IntegrityError:
        raise ValueError(f"Category '{normalized['name']}' already exists.")
    finally:
        conn.close()
    if not row:
        raise ValueError("Failed to load created category.")
    return _row_to_page_category(row)


def _update_page_category(db_path: Path, category_id: int, payload: object) -> dict[str, object]:
    _init_page_categories_db(db_path)
    normalized = _normalize_page_category_payload(payload, require_name=True)
    cid = int(category_id)
    now = _utc_now_iso()
    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    try:
        existing = conn.execute("SELECT id FROM page_categories WHERE id = ?", (cid,)).fetchone()
        if not existing:
            raise LookupError(f"Category '{cid}' not found.")
        conn.execute(
            """
            UPDATE page_categories
            SET name = ?, icon_name = ?, display_in_navigation = ?, display_order = ?, is_active = ?, updated_at_utc = ?
            WHERE id = ?
            """,
            (
                normalized["name"],
                normalized["icon_name"],
                normalized["display_in_navigation"],
                normalized["display_order"],
                normalized["is_active"],
                now,
                cid,
            ),
        )
        conn.commit()
        row = conn.execute(
            """
            SELECT id, name, icon_name, display_in_navigation, display_order, is_active, created_at_utc, updated_at_utc
            FROM page_categories
            WHERE id = ?
            """,
            (cid,),
        ).fetchone()
    except sqlite3.IntegrityError:
        raise ValueError(f"Category '{normalized['name']}' already exists.")
    finally:
        conn.close()
    if not row:
        raise LookupError(f"Category '{cid}' not found.")
    return _row_to_page_category(row)


def _delete_page_category(db_path: Path, category_id: int) -> int:
    _init_page_categories_db(db_path)
    cid = int(category_id)
    conn = sqlite3.connect(db_path)
    try:
        conn.execute("DELETE FROM page_category_assignments WHERE category_id = ?", (cid,))
        cur = conn.execute("DELETE FROM page_categories WHERE id = ?", (cid,))
        conn.commit()
    finally:
        conn.close()
    if int(cur.rowcount or 0) <= 0:
        raise LookupError(f"Category '{cid}' not found.")
    return cid


def _save_page_categories_payload(db_path: Path, payload: object) -> dict[str, object]:
    _init_page_categories_db(db_path)
    raw = payload if isinstance(payload, dict) else {}
    incoming_categories_raw = raw.get("categories")
    incoming_assignments_raw = raw.get("assignments")
    incoming_page_overrides_raw = raw.get("page_overrides")
    incoming_categories = incoming_categories_raw if isinstance(incoming_categories_raw, list) else []
    incoming_assignments = incoming_assignments_raw if isinstance(incoming_assignments_raw, list) else []
    incoming_page_overrides = incoming_page_overrides_raw if isinstance(incoming_page_overrides_raw, list) else []
    replace_page_overrides = isinstance(incoming_page_overrides_raw, list)

    now = _utc_now_iso()
    valid_pages = _base_page_catalog()
    valid_page_keys = {item["page_key"] for item in valid_pages}
    valid_pages_by_key = {item["page_key"]: item for item in valid_pages}
    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    try:
        existing_rows = conn.execute(
            "SELECT id, name, icon_name, display_in_navigation, display_order, is_active FROM page_categories ORDER BY id ASC"
        ).fetchall()
        existing_by_id = {int(row["id"]): row for row in existing_rows}

        keep_ids: set[int] = set()
        for item in incoming_categories:
            normalized = _normalize_page_category_payload(item, require_name=True)
            requested_id = int(normalized.get("id") or 0)
            if requested_id > 0 and requested_id in existing_by_id:
                conn.execute(
                    """
                    UPDATE page_categories
                    SET name = ?, icon_name = ?, display_in_navigation = ?, display_order = ?, is_active = ?, updated_at_utc = ?
                    WHERE id = ?
                    """,
                    (
                        normalized["name"],
                        normalized["icon_name"],
                        normalized["display_in_navigation"],
                        normalized["display_order"],
                        normalized["is_active"],
                        now,
                        requested_id,
                    ),
                )
                keep_ids.add(requested_id)
            else:
                cur = conn.execute(
                    """
                    INSERT INTO page_categories(name, icon_name, display_in_navigation, display_order, is_active, created_at_utc, updated_at_utc)
                    VALUES(?, ?, ?, ?, ?, ?, ?)
                    """,
                    (
                        normalized["name"],
                        normalized["icon_name"],
                        normalized["display_in_navigation"],
                        normalized["display_order"],
                        normalized["is_active"],
                        now,
                        now,
                    ),
                )
                keep_ids.add(int(cur.lastrowid or 0))

        if incoming_categories:
            existing_ids = set(existing_by_id.keys())
            delete_ids = existing_ids - keep_ids
            for cid in delete_ids:
                conn.execute("DELETE FROM page_category_assignments WHERE category_id = ?", (cid,))
                conn.execute("DELETE FROM page_categories WHERE id = ?", (cid,))

        active_category_rows = conn.execute(
            "SELECT id FROM page_categories WHERE is_active = 1"
        ).fetchall()
        valid_category_ids = {int(row["id"]) for row in active_category_rows}

        conn.execute("DELETE FROM page_category_assignments")
        seen_pairs: set[tuple[str, int]] = set()
        for item in incoming_assignments:
            normalized_assignment = _normalize_page_assignment_payload(item, valid_page_keys, valid_category_ids)
            pair = (str(normalized_assignment["page_key"]), int(normalized_assignment["category_id"]))
            if pair in seen_pairs:
                continue
            seen_pairs.add(pair)
            conn.execute(
                """
                INSERT INTO page_category_assignments(page_key, page_type, category_id, created_at_utc, updated_at_utc)
                VALUES(?, ?, ?, ?, ?)
                """,
                (
                    normalized_assignment["page_key"],
                    normalized_assignment["page_type"],
                    normalized_assignment["category_id"],
                    now,
                    now,
                ),
            )
        if replace_page_overrides:
            conn.execute("DELETE FROM page_display_name_overrides")
            seen_override_keys: set[str] = set()
            for item in incoming_page_overrides:
                normalized_override = _normalize_page_display_name_payload(item, valid_pages_by_key)
                page_key = normalized_override["page_key"]
                if page_key in seen_override_keys:
                    continue
                seen_override_keys.add(page_key)
                display_name = normalized_override["display_name"]
                if not display_name:
                    continue
                conn.execute(
                    """
                    INSERT INTO page_display_name_overrides(page_key, display_name, updated_at_utc)
                    VALUES(?, ?, ?)
                    """,
                    (
                        page_key,
                        display_name,
                        now,
                    ),
                )
        conn.commit()
    except sqlite3.IntegrityError as exc:
        raise ValueError(f"Failed to save page categories payload: {exc}")
    finally:
        conn.close()
    return _load_page_categories(db_path)


def _sort_nav_items(items: list[dict[str, object]]) -> list[dict[str, object]]:
    return sorted(items, key=lambda item: (int(item.get("default_nav_order") or 0), _to_text(item.get("title")).casefold()))


def _build_navigation_from_page_categories(db_path: Path) -> dict[str, object]:
    state = _load_page_categories(db_path)
    categories = [item for item in state["categories"] if bool(item.get("is_active"))]
    if not categories:
        return {"enabled": False}

    visible_categories = [
        item for item in categories
        if bool(item.get("display_in_navigation"))
    ]
    visible_categories = sorted(
        visible_categories,
        key=lambda item: (int(item.get("display_order") or 0), _to_text(item.get("name")).casefold(), int(item.get("id") or 0)),
    )
    visible_ids = {int(item.get("id") or 0) for item in visible_categories}

    effective_catalog = state.get("page_catalog") if isinstance(state.get("page_catalog"), list) else _page_catalog(db_path)
    report_by_key = {str(item["page_key"]): dict(item) for item in effective_catalog if _to_text(item.get("page_type")) == "report"}
    admin_by_key = {str(item["page_key"]): dict(item) for item in effective_catalog if _to_text(item.get("page_type")) == "configuration"}
    assignment_map: dict[str, set[int]] = defaultdict(set)
    for row in state["assignments"]:
        category_id = int(row.get("category_id") or 0)
        if category_id not in visible_ids:
            continue
        page_key = _to_text(row.get("page_key"))
        if page_key:
            assignment_map[page_key].add(category_id)

    report_categories: list[dict[str, object]] = []
    report_assigned_keys: set[str] = set()
    for category in visible_categories:
        cid = int(category.get("id") or 0)
        items = [item for key, item in report_by_key.items() if cid in assignment_map.get(key, set())]
        if not items:
            continue
        report_assigned_keys.update({str(item["page_key"]) for item in items})
        report_categories.append(
            {
                "id": cid,
                "name": _to_text(category.get("name")),
                "icon_name": _normalize_google_icon_name(category.get("icon_name")),
                "items": _sort_nav_items(items),
            }
        )

    admin_categories: list[dict[str, object]] = []
    admin_assigned_keys: set[str] = set()
    for category in visible_categories:
        cid = int(category.get("id") or 0)
        items = [item for key, item in admin_by_key.items() if cid in assignment_map.get(key, set())]
        if not items:
            continue
        admin_assigned_keys.update({str(item["page_key"]) for item in items})
        admin_categories.append(
            {
                "id": cid,
                "name": _to_text(category.get("name")),
                "icon_name": _normalize_google_icon_name(category.get("icon_name")),
                "items": _sort_nav_items(items),
            }
        )

    uncategorized_reports = _sort_nav_items([item for key, item in report_by_key.items() if key not in report_assigned_keys])
    uncategorized_admin = _sort_nav_items([item for key, item in admin_by_key.items() if key not in admin_assigned_keys])
    return {
        "enabled": True,
        "reports": {
            "items": uncategorized_reports,
            "categories": report_categories,
        },
        "admin_settings": {
            "items": uncategorized_admin,
            "categories": admin_categories,
        },
    }


def _resolve_capacity_runtime_paths(base_dir: Path) -> dict[str, Path]:
    db_name = os.getenv("JIRA_ASSIGNEE_HOURS_CAPACITY_DB_PATH", DEFAULT_CAPACITY_DB).strip() or DEFAULT_CAPACITY_DB
    leave_name = os.getenv("JIRA_LEAVE_REPORT_XLSX_PATH", DEFAULT_LEAVE_REPORT_INPUT_XLSX).strip() or DEFAULT_LEAVE_REPORT_INPUT_XLSX
    summary_name = (
        os.getenv("JIRA_ASSIGNEE_HOURS_SUMMARY_XLSX_PATH", DEFAULT_SUMMARY_OUTPUT_XLSX).strip()
        or DEFAULT_SUMMARY_OUTPUT_XLSX
    )

    db_path = Path(db_name)
    if not db_path.is_absolute():
        db_path = base_dir / db_path

    leave_report_path = Path(leave_name)
    if not leave_report_path.is_absolute():
        leave_report_path = base_dir / leave_report_path

    summary_path = Path(summary_name)
    if not summary_path.is_absolute():
        summary_path = base_dir / summary_path

    return {
        "db_path": db_path,
        "leave_report_path": leave_report_path,
        "summary_path": summary_path,
    }


def clear_planned_vs_dispensed_cache_tables(db_path: Path) -> None:
    """Remove only the planned-vs-dispensed cache tables from the app DB."""
    db_path = Path(db_path)
    db_path.parent.mkdir(parents=True, exist_ok=True)
    conn = sqlite3.connect(db_path)
    try:
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS planned_vs_dispensed_cache (
                cache_key TEXT PRIMARY KEY,
                from_date TEXT NOT NULL,
                to_date TEXT NOT NULL,
                mode TEXT NOT NULL,
                project_scope TEXT NOT NULL DEFAULT '',
                payload_json TEXT NOT NULL,
                fetched_at TEXT NOT NULL DEFAULT (datetime('now'))
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS planned_vs_dispensed_response_cache (
                cache_key TEXT PRIMARY KEY,
                endpoint TEXT NOT NULL,
                from_date TEXT NOT NULL,
                to_date TEXT NOT NULL,
                mode TEXT NOT NULL,
                project_scope TEXT NOT NULL DEFAULT '',
                statuses_scope TEXT NOT NULL DEFAULT '',
                assignees_scope TEXT NOT NULL DEFAULT '',
                project_key TEXT NOT NULL DEFAULT '',
                payload_json TEXT NOT NULL,
                fetched_at TEXT NOT NULL DEFAULT (datetime('now'))
            )
            """
        )
        conn.execute("DELETE FROM planned_vs_dispensed_cache")
        conn.execute("DELETE FROM planned_vs_dispensed_response_cache")
        conn.commit()
    finally:
        conn.close()


def _resolve_exports_db_path(base_dir: Path) -> Path:
    db_name = os.getenv("JIRA_EXPORTS_DB_PATH", DEFAULT_EXPORTS_DB).strip() or DEFAULT_EXPORTS_DB
    db_path = Path(db_name)
    if not db_path.is_absolute():
        db_path = base_dir / db_path
    return db_path


SQL_CONSOLE_ALLOWED_START_KEYWORDS = ("SELECT", "WITH", "EXPLAIN", "PRAGMA")
SQL_CONSOLE_ALLOWED_PRAGMAS = {
    "collation_list",
    "compile_options",
    "database_list",
    "foreign_key_list",
    "function_list",
    "index_info",
    "index_list",
    "index_xinfo",
    "module_list",
    "pragma_list",
    "table_info",
    "table_list",
    "table_xinfo",
}
SQL_CONSOLE_MAX_ROWS = 500
SQL_CONSOLE_EXPORT_MAX_ROWS = 20000


def _sql_console_split_statements(sql: str) -> list[str]:
    statements: list[str] = []
    current: list[str] = []
    i = 0
    in_single = False
    in_double = False
    in_line_comment = False
    in_block_comment = False
    while i < len(sql):
        ch = sql[i]
        nxt = sql[i + 1] if i + 1 < len(sql) else ""
        if in_line_comment:
            if ch == "\n":
                in_line_comment = False
                current.append(ch)
            i += 1
            continue
        if in_block_comment:
            if ch == "*" and nxt == "/":
                in_block_comment = False
                i += 2
                continue
            i += 1
            continue
        if not in_single and not in_double:
            if ch == "-" and nxt == "-":
                in_line_comment = True
                i += 2
                continue
            if ch == "/" and nxt == "*":
                in_block_comment = True
                i += 2
                continue
        if ch == "'" and not in_double:
            if in_single and nxt == "'":
                current.extend([ch, nxt])
                i += 2
                continue
            in_single = not in_single
            current.append(ch)
            i += 1
            continue
        if ch == '"' and not in_single:
            if in_double and nxt == '"':
                current.extend([ch, nxt])
                i += 2
                continue
            in_double = not in_double
            current.append(ch)
            i += 1
            continue
        if ch == ";" and not in_single and not in_double:
            statement = "".join(current).strip()
            if statement:
                statements.append(statement)
            current = []
            i += 1
            continue
        current.append(ch)
        i += 1
    statement = "".join(current).strip()
    if statement:
        statements.append(statement)
    return statements


def _sql_console_principal_keyword(sql: str) -> str:
    match = re.match(r"^\s*([A-Za-z]+)", sql)
    return match.group(1).upper() if match else ""


def _normalize_sql_console_query(sql: object) -> str:
    query = _to_text(sql).strip()
    if not query:
        raise ValueError("SQL is required.")
    statements = _sql_console_split_statements(query)
    if len(statements) != 1:
        raise ValueError("Exactly one SQL statement is allowed.")
    normalized = statements[0].strip()
    keyword = _sql_console_principal_keyword(normalized)
    if keyword not in SQL_CONSOLE_ALLOWED_START_KEYWORDS:
        raise ValueError("Only read-only SELECT, WITH, EXPLAIN, and PRAGMA statements are allowed.")
    upper_sql = normalized.upper()
    forbidden_tokens = (
        "ATTACH ",
        "DETACH ",
        "INSERT ",
        "UPDATE ",
        "DELETE ",
        "DROP ",
        "ALTER ",
        "CREATE ",
        "REPLACE ",
        "VACUUM ",
        "REINDEX ",
        "ANALYZE ",
        "BEGIN ",
        "COMMIT ",
        "ROLLBACK ",
        "SAVEPOINT ",
        "RELEASE ",
    )
    if any(token in upper_sql for token in forbidden_tokens):
        raise ValueError("Only read-only SQL is allowed.")
    if keyword == "PRAGMA":
        remainder = re.sub(r"^\s*PRAGMA\s+", "", normalized, flags=re.IGNORECASE).strip()
        pragma_name = re.split(r"[\s(=]", remainder, maxsplit=1)[0].strip().lower()
        if "." in pragma_name:
            pragma_name = pragma_name.split(".", 1)[1]
        if "=" in remainder or pragma_name not in SQL_CONSOLE_ALLOWED_PRAGMAS:
            raise ValueError("Only read-only schema PRAGMA statements are allowed.")
    return normalized


def _sql_console_target_path(base_dir: Path, canonical_db_path: Path, database_key: object) -> tuple[str, Path]:
    key = _to_text(database_key).strip().lower() or "canonical"
    if key == "canonical":
        return key, canonical_db_path
    if key == "exports":
        return key, _resolve_exports_db_path(base_dir)
    raise ValueError("database must be 'canonical' or 'exports'.")


def _sqlite_readonly_uri(db_path: Path) -> str:
    return db_path.resolve().as_uri().replace("file:///", "file:/") + "?mode=ro"


def _epf_retention_runs() -> int:
    raw = _to_text(os.getenv("EPF_REFRESH_RETAIN_RUNS", str(EPF_DEFAULT_RETENTION_RUNS)))
    try:
        value = int(raw)
    except (TypeError, ValueError):
        value = EPF_DEFAULT_RETENTION_RUNS
    return max(1, value)


def _epf_now_utc() -> str:
    return datetime.now(timezone.utc).isoformat()


def _sqlite_column_exists(conn: sqlite3.Connection, table_name: str, column_name: str) -> bool:
    rows = conn.execute(f"PRAGMA table_info({table_name})").fetchall()
    for row in rows:
        # pragma table_info columns: cid, name, type, notnull, dflt_value, pk
        if len(row) > 1 and _to_text(row[1]) == column_name:
            return True
    return False


def _init_epf_refresh_db(db_path: Path) -> None:
    db_path.parent.mkdir(parents=True, exist_ok=True)
    with sqlite3.connect(db_path) as conn:
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS epf_refresh_runs (
                run_id TEXT PRIMARY KEY,
                started_at_utc TEXT NOT NULL,
                ended_at_utc TEXT,
                status TEXT NOT NULL,
                trigger_source TEXT NOT NULL DEFAULT '',
                error_message TEXT NOT NULL DEFAULT '',
                stats_json TEXT NOT NULL DEFAULT '{}'
            )
            """
        )
        if not _sqlite_column_exists(conn, "epf_refresh_runs", "progress_step"):
            conn.execute("ALTER TABLE epf_refresh_runs ADD COLUMN progress_step TEXT NOT NULL DEFAULT ''")
        if not _sqlite_column_exists(conn, "epf_refresh_runs", "progress_pct"):
            conn.execute("ALTER TABLE epf_refresh_runs ADD COLUMN progress_pct INTEGER NOT NULL DEFAULT 0")
        if not _sqlite_column_exists(conn, "epf_refresh_runs", "cancel_requested"):
            conn.execute("ALTER TABLE epf_refresh_runs ADD COLUMN cancel_requested INTEGER NOT NULL DEFAULT 0")
        if not _sqlite_column_exists(conn, "epf_refresh_runs", "updated_at_utc"):
            conn.execute("ALTER TABLE epf_refresh_runs ADD COLUMN updated_at_utc TEXT NOT NULL DEFAULT ''")
        now_for_backfill = _epf_now_utc()
        conn.execute(
            """
            UPDATE epf_refresh_runs
            SET updated_at_utc = COALESCE(NULLIF(updated_at_utc, ''), started_at_utc, ?)
            WHERE COALESCE(updated_at_utc, '') = ''
            """,
            (now_for_backfill,),
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS epf_refresh_state (
                id INTEGER PRIMARY KEY CHECK(id = 1),
                active_run_id TEXT NOT NULL DEFAULT '',
                last_success_run_id TEXT NOT NULL DEFAULT '',
                updated_at_utc TEXT NOT NULL
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS epf_work_items (
                run_id TEXT NOT NULL,
                issue_key TEXT NOT NULL,
                project_key TEXT NOT NULL DEFAULT '',
                issue_type TEXT NOT NULL DEFAULT '',
                fix_type TEXT NOT NULL DEFAULT '',
                summary TEXT NOT NULL DEFAULT '',
                status TEXT NOT NULL DEFAULT '',
                assignee TEXT NOT NULL DEFAULT '',
                start_date TEXT NOT NULL DEFAULT '',
                due_date TEXT NOT NULL DEFAULT '',
                original_estimate_hours REAL NOT NULL DEFAULT 0,
                parent_issue_key TEXT NOT NULL DEFAULT ''
            )
            """
        )
        conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_epf_work_items_run_issue ON epf_work_items(run_id, issue_key)"
        )
        conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_epf_work_items_run_assignee ON epf_work_items(run_id, assignee)"
        )
        conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_epf_work_items_run_project ON epf_work_items(run_id, project_key)"
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS epf_worklogs (
                run_id TEXT NOT NULL,
                issue_id TEXT NOT NULL,
                issue_assignee TEXT NOT NULL DEFAULT '',
                worklog_date TEXT NOT NULL DEFAULT '',
                hours_logged REAL NOT NULL DEFAULT 0,
                project_key TEXT NOT NULL DEFAULT '',
                is_bug INTEGER NOT NULL DEFAULT 0,
                fix_type TEXT NOT NULL DEFAULT '',
                item_summary TEXT NOT NULL DEFAULT '',
                item_status TEXT NOT NULL DEFAULT '',
                item_issue_type TEXT NOT NULL DEFAULT '',
                item_assignee TEXT NOT NULL DEFAULT '',
                item_parent_issue_key TEXT NOT NULL DEFAULT '',
                item_start_date TEXT NOT NULL DEFAULT '',
                item_due_date TEXT NOT NULL DEFAULT '',
                story_due_date TEXT NOT NULL DEFAULT '',
                original_estimate_hours REAL NOT NULL DEFAULT 0
            )
            """
        )
        conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_epf_worklogs_run_issue ON epf_worklogs(run_id, issue_id)"
        )
        conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_epf_worklogs_run_assignee ON epf_worklogs(run_id, issue_assignee)"
        )
        conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_epf_worklogs_run_project ON epf_worklogs(run_id, project_key)"
        )
        conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_epf_worklogs_run_date ON epf_worklogs(run_id, worklog_date)"
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS epf_leave_rows (
                run_id TEXT NOT NULL,
                assignee TEXT NOT NULL DEFAULT '',
                period_day TEXT NOT NULL DEFAULT '',
                unplanned_taken_hours REAL NOT NULL DEFAULT 0,
                planned_taken_hours REAL NOT NULL DEFAULT 0
            )
            """
        )
        conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_epf_leave_rows_run_assignee ON epf_leave_rows(run_id, assignee)"
        )
        conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_epf_leave_rows_run_day ON epf_leave_rows(run_id, period_day)"
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS epf_leave_issue_keys (
                run_id TEXT NOT NULL,
                issue_key TEXT NOT NULL
            )
            """
        )
        conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_epf_leave_issue_keys_run_issue ON epf_leave_issue_keys(run_id, issue_key)"
        )
        row = conn.execute("SELECT id FROM epf_refresh_state WHERE id = 1").fetchone()
        if not row:
            now = _epf_now_utc()
            conn.execute(
                "INSERT INTO epf_refresh_state(id, active_run_id, last_success_run_id, updated_at_utc) VALUES (1, '', '', ?)",
                (now,),
            )
        conn.commit()


def _epf_insert_run_data(
    db_path: Path,
    run_id: str,
    work_items: dict[str, dict],
    worklogs: list[dict],
    leave_rows: list[dict],
    leave_issue_keys: list[str],
    replace_run: bool = True,
) -> dict[str, int]:
    work_item_rows = []
    for item in (work_items or {}).values():
        work_item_rows.append(
            (
                run_id,
                _to_text(item.get("issue_key")).upper(),
                _to_text(item.get("project_key")).upper(),
                _to_text(item.get("issue_type")),
                _to_text(item.get("fix_type")).lower(),
                _to_text(item.get("summary")),
                _to_text(item.get("status")),
                _to_text(item.get("assignee")),
                _to_text(item.get("start_date")),
                _to_text(item.get("due_date")),
                float(item.get("original_estimate_hours") or 0),
                _to_text(item.get("parent_issue_key")).upper(),
            )
        )

    worklog_rows = []
    for row in worklogs or []:
        worklog_rows.append(
            (
                run_id,
                _to_text(row.get("issue_id")).upper(),
                _to_text(row.get("issue_assignee")) or "Unassigned",
                _to_text(row.get("worklog_date")),
                float(row.get("hours_logged") or 0),
                _to_text(row.get("project_key")).upper(),
                1 if bool(row.get("is_bug")) else 0,
                _to_text(row.get("fix_type")).lower(),
                _to_text(row.get("item_summary")),
                _to_text(row.get("item_status")),
                _to_text(row.get("item_issue_type")),
                _to_text(row.get("item_assignee")),
                _to_text(row.get("item_parent_issue_key")).upper(),
                _to_text(row.get("item_start_date")),
                _to_text(row.get("item_due_date")),
                _to_text(row.get("story_due_date")),
                float(row.get("original_estimate_hours") or 0),
            )
        )

    leave_data_rows = []
    for row in leave_rows or []:
        leave_data_rows.append(
            (
                run_id,
                _to_text(row.get("assignee")) or "Unassigned",
                _to_text(row.get("period_day")),
                float(row.get("unplanned_taken_hours") or 0),
                float(row.get("planned_taken_hours") or 0),
            )
        )

    leave_key_rows = [(run_id, _to_text(x).upper()) for x in (leave_issue_keys or []) if _to_text(x)]

    with sqlite3.connect(db_path) as conn:
        if replace_run:
            conn.execute("DELETE FROM epf_work_items WHERE run_id = ?", (run_id,))
            conn.execute("DELETE FROM epf_worklogs WHERE run_id = ?", (run_id,))
            conn.execute("DELETE FROM epf_leave_rows WHERE run_id = ?", (run_id,))
            conn.execute("DELETE FROM epf_leave_issue_keys WHERE run_id = ?", (run_id,))
        if work_item_rows:
            conn.executemany(
                """
                INSERT INTO epf_work_items(
                    run_id, issue_key, project_key, issue_type, fix_type, summary, status, assignee,
                    start_date, due_date, original_estimate_hours, parent_issue_key
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                work_item_rows,
            )
        if worklog_rows:
            conn.executemany(
                """
                INSERT INTO epf_worklogs(
                    run_id, issue_id, issue_assignee, worklog_date, hours_logged, project_key, is_bug,
                    fix_type, item_summary, item_status, item_issue_type, item_assignee, item_parent_issue_key,
                    item_start_date, item_due_date, story_due_date, original_estimate_hours
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                worklog_rows,
            )
        if leave_data_rows:
            conn.executemany(
                """
                INSERT INTO epf_leave_rows(
                    run_id, assignee, period_day, unplanned_taken_hours, planned_taken_hours
                ) VALUES (?, ?, ?, ?, ?)
                """,
                leave_data_rows,
            )
        if leave_key_rows:
            conn.executemany(
                "INSERT INTO epf_leave_issue_keys(run_id, issue_key) VALUES (?, ?)",
                leave_key_rows,
            )
        conn.commit()
    return {
        "work_items": len(work_item_rows),
        "worklogs": len(worklog_rows),
        "leave_rows": len(leave_data_rows),
        "leave_issue_keys": len(leave_key_rows),
    }


def _epf_mark_run_status(
    db_path: Path,
    run_id: str,
    status: str,
    error_message: str = "",
    stats: dict[str, object] | None = None,
    activate: bool = False,
) -> None:
    now = _epf_now_utc()
    stats_json = json.dumps(stats or {}, ensure_ascii=True)
    with sqlite3.connect(db_path) as conn:
        conn.execute(
            """
            UPDATE epf_refresh_runs
            SET ended_at_utc = ?, status = ?, error_message = ?, stats_json = ?, updated_at_utc = ?
            WHERE run_id = ?
            """,
            (now, status, _to_text(error_message), stats_json, now, run_id),
        )
        if activate and status == "success":
            conn.execute(
                """
                UPDATE epf_refresh_state
                SET active_run_id = ?, last_success_run_id = ?, updated_at_utc = ?
                WHERE id = 1
                """,
                (run_id, run_id, now),
            )
        conn.commit()


def _epf_update_run_progress(db_path: Path, run_id: str, step: str, progress_pct: int) -> None:
    if not run_id:
        return
    now = _epf_now_utc()
    progress = max(0, min(100, int(progress_pct or 0)))
    with sqlite3.connect(db_path) as conn:
        conn.execute(
            """
            UPDATE epf_refresh_runs
            SET progress_step = ?, progress_pct = ?, updated_at_utc = ?
            WHERE run_id = ?
            """,
            (_to_text(step), progress, now, run_id),
        )
        conn.commit()


def _epf_update_run_progress_and_stats(
    db_path: Path, run_id: str, step: str, progress_pct: int, stats: dict[str, object] | None = None,
) -> None:
    if not run_id:
        return
    now = _epf_now_utc()
    progress = max(0, min(100, int(progress_pct or 0)))
    with sqlite3.connect(db_path) as conn:
        if stats is not None:
            stats_json = json.dumps(stats, ensure_ascii=True)
            conn.execute(
                """
                UPDATE epf_refresh_runs
                SET progress_step = ?, progress_pct = ?, stats_json = ?, updated_at_utc = ?
                WHERE run_id = ?
                """,
                (_to_text(step), progress, stats_json, now, run_id),
            )
        else:
            conn.execute(
                """
                UPDATE epf_refresh_runs
                SET progress_step = ?, progress_pct = ?, updated_at_utc = ?
                WHERE run_id = ?
                """,
                (_to_text(step), progress, now, run_id),
            )
        conn.commit()


def _epf_discover_assignees(db_path: Path, base_dir: Path) -> list[str]:
    active_id = _epf_active_run_id(db_path)
    if active_id:
        with sqlite3.connect(db_path) as conn:
            rows = conn.execute(
                "SELECT DISTINCT assignee FROM epf_work_items WHERE run_id = ? AND assignee != '' AND assignee IS NOT NULL",
                (active_id,),
            ).fetchall()
        assignees = sorted({_to_text(r[0]) for r in rows if _to_text(r[0])})
        if assignees:
            return assignees
    xlsx_path = base_dir / "assignee_hours_report.xlsx"
    if xlsx_path.exists():
        try:
            from openpyxl import load_workbook

            wb = load_workbook(xlsx_path, read_only=True, data_only=True)
            ws = wb.active
            headers = [_to_text(c.value).lower() for c in next(ws.iter_rows(min_row=1, max_row=1))]
            col_idx = -1
            for i, h in enumerate(headers):
                if h in ("issue_assignee", "assignee"):
                    col_idx = i
                    break
            found: set[str] = set()
            if col_idx >= 0:
                for row in ws.iter_rows(min_row=2):
                    if col_idx < len(row):
                        val = _to_text(row[col_idx].value)
                        if val:
                            found.add(val)
            wb.close()
            return sorted(found) if found else []
        except Exception:
            pass
    return []


def _epf_is_cancel_requested(db_path: Path, run_id: str) -> bool:
    if not run_id:
        return False
    with sqlite3.connect(db_path) as conn:
        row = conn.execute(
            "SELECT cancel_requested FROM epf_refresh_runs WHERE run_id = ?",
            (run_id,),
        ).fetchone()
    return bool(int(row[0] or 0)) if row else False


def _epf_request_cancel(db_path: Path, run_id: str) -> bool:
    if not run_id:
        return False
    now = _epf_now_utc()
    with sqlite3.connect(db_path) as conn:
        cur = conn.execute(
            """
            UPDATE epf_refresh_runs
            SET cancel_requested = 1, updated_at_utc = ?
            WHERE run_id = ? AND status = 'running'
            """,
            (now, run_id),
        )
        conn.commit()
        return int(cur.rowcount or 0) > 0


def _epf_get_run(db_path: Path, run_id: str) -> dict[str, object] | None:
    if not run_id:
        return None
    with sqlite3.connect(db_path) as conn:
        conn.row_factory = sqlite3.Row
        row = conn.execute(
            """
            SELECT
                run_id, started_at_utc, ended_at_utc, status, trigger_source, error_message,
                stats_json, progress_step, progress_pct, cancel_requested, updated_at_utc
            FROM epf_refresh_runs
            WHERE run_id = ?
            """,
            (run_id,),
        ).fetchone()
    return dict(row) if row else None


def _epf_find_running_run(db_path: Path) -> dict[str, object] | None:
    with sqlite3.connect(db_path) as conn:
        conn.row_factory = sqlite3.Row
        row = conn.execute(
            """
            SELECT
                run_id, started_at_utc, ended_at_utc, status, trigger_source, error_message,
                stats_json, progress_step, progress_pct, cancel_requested, updated_at_utc
            FROM epf_refresh_runs
            WHERE status = 'running'
            ORDER BY started_at_utc DESC
            LIMIT 1
            """
        ).fetchone()
    return dict(row) if row else None


def _epf_prune_old_runs(db_path: Path, keep_runs: int) -> None:
    keep = max(1, int(keep_runs or 1))
    with sqlite3.connect(db_path) as conn:
        state_row = conn.execute(
            "SELECT active_run_id FROM epf_refresh_state WHERE id = 1"
        ).fetchone()
        active_run_id = _to_text(state_row[0] if state_row else "")
        rows = conn.execute(
            """
            SELECT run_id FROM epf_refresh_runs
            WHERE status = 'success'
            ORDER BY ended_at_utc DESC, started_at_utc DESC
            """
        ).fetchall()
        keep_ids = {_to_text(r[0]) for r in rows[:keep]}
        if active_run_id:
            keep_ids.add(active_run_id)
        delete_ids = [_to_text(r[0]) for r in rows if _to_text(r[0]) and _to_text(r[0]) not in keep_ids]
        for run_id in delete_ids:
            conn.execute("DELETE FROM epf_work_items WHERE run_id = ?", (run_id,))
            conn.execute("DELETE FROM epf_worklogs WHERE run_id = ?", (run_id,))
            conn.execute("DELETE FROM epf_leave_rows WHERE run_id = ?", (run_id,))
            conn.execute("DELETE FROM epf_leave_issue_keys WHERE run_id = ?", (run_id,))
            conn.execute("DELETE FROM epf_refresh_runs WHERE run_id = ?", (run_id,))
        conn.commit()


def _epf_active_run_id(db_path: Path) -> str:
    with sqlite3.connect(db_path) as conn:
        row = conn.execute(
            "SELECT active_run_id FROM epf_refresh_state WHERE id = 1"
        ).fetchone()
    return _to_text(row[0] if row else "")


def _epf_clone_run_snapshot(db_path: Path, source_run_id: str, target_run_id: str) -> None:
    if not source_run_id or not target_run_id:
        return
    with sqlite3.connect(db_path) as conn:
        conn.execute(
            """
            INSERT INTO epf_work_items(
                run_id, issue_key, project_key, issue_type, fix_type, summary, status, assignee,
                start_date, due_date, original_estimate_hours, parent_issue_key
            )
            SELECT ?, issue_key, project_key, issue_type, fix_type, summary, status, assignee,
                   start_date, due_date, original_estimate_hours, parent_issue_key
            FROM epf_work_items
            WHERE run_id = ?
            """,
            (target_run_id, source_run_id),
        )
        conn.execute(
            """
            INSERT INTO epf_worklogs(
                run_id, issue_id, issue_assignee, worklog_date, hours_logged, project_key, is_bug, fix_type,
                item_summary, item_status, item_issue_type, item_assignee, item_parent_issue_key, item_start_date,
                item_due_date, story_due_date, original_estimate_hours
            )
            SELECT ?, issue_id, issue_assignee, worklog_date, hours_logged, project_key, is_bug, fix_type,
                   item_summary, item_status, item_issue_type, item_assignee, item_parent_issue_key, item_start_date,
                   item_due_date, story_due_date, original_estimate_hours
            FROM epf_worklogs
            WHERE run_id = ?
            """,
            (target_run_id, source_run_id),
        )
        conn.execute(
            """
            INSERT INTO epf_leave_rows(
                run_id, assignee, period_day, unplanned_taken_hours, planned_taken_hours
            )
            SELECT ?, assignee, period_day, unplanned_taken_hours, planned_taken_hours
            FROM epf_leave_rows
            WHERE run_id = ?
            """,
            (target_run_id, source_run_id),
        )
        conn.execute(
            """
            INSERT INTO epf_leave_issue_keys(run_id, issue_key)
            SELECT ?, issue_key
            FROM epf_leave_issue_keys
            WHERE run_id = ?
            """,
            (target_run_id, source_run_id),
        )
        conn.commit()


def _me_retention_runs() -> int:
    raw = _to_text(os.getenv("MISSED_ENTRIES_REFRESH_RETAIN_RUNS", str(ME_DEFAULT_RETENTION_RUNS)))
    try:
        value = int(raw)
    except (TypeError, ValueError):
        value = ME_DEFAULT_RETENTION_RUNS
    return max(1, value)


def _me_now_utc() -> str:
    return datetime.now(timezone.utc).isoformat()


def _init_missed_entries_refresh_db(db_path: Path) -> None:
    db_path.parent.mkdir(parents=True, exist_ok=True)
    with sqlite3.connect(db_path) as conn:
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS me_refresh_runs (
                run_id TEXT PRIMARY KEY,
                started_at_utc TEXT NOT NULL,
                ended_at_utc TEXT,
                status TEXT NOT NULL,
                trigger_source TEXT NOT NULL DEFAULT '',
                error_message TEXT NOT NULL DEFAULT '',
                stats_json TEXT NOT NULL DEFAULT '{}',
                progress_step TEXT NOT NULL DEFAULT '',
                progress_pct INTEGER NOT NULL DEFAULT 0,
                cancel_requested INTEGER NOT NULL DEFAULT 0,
                updated_at_utc TEXT NOT NULL DEFAULT ''
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS me_refresh_state (
                id INTEGER PRIMARY KEY CHECK(id = 1),
                active_run_id TEXT NOT NULL DEFAULT '',
                last_success_run_id TEXT NOT NULL DEFAULT '',
                updated_at_utc TEXT NOT NULL
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS me_snapshot_rows (
                run_id TEXT NOT NULL,
                issue_key TEXT NOT NULL,
                issue_type TEXT NOT NULL DEFAULT '',
                assignee TEXT NOT NULL DEFAULT '',
                summary TEXT NOT NULL DEFAULT '',
                jira_start_date TEXT NOT NULL DEFAULT '',
                jira_due_date TEXT NOT NULL DEFAULT '',
                original_estimate TEXT NOT NULL DEFAULT '',
                resource_logged_hours TEXT NOT NULL DEFAULT '',
                jira_url TEXT NOT NULL DEFAULT ''
            )
            """
        )
        conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_me_snapshot_rows_run_issue ON me_snapshot_rows(run_id, issue_key)"
        )
        conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_me_snapshot_rows_run_assignee ON me_snapshot_rows(run_id, assignee)"
        )
        row = conn.execute("SELECT id FROM me_refresh_state WHERE id = 1").fetchone()
        if not row:
            now = _me_now_utc()
            conn.execute(
                "INSERT INTO me_refresh_state(id, active_run_id, last_success_run_id, updated_at_utc) VALUES (1, '', '', ?)",
                (now,),
            )
        conn.commit()


def _me_get_run(db_path: Path, run_id: str) -> dict[str, object] | None:
    run_id_text = _to_text(run_id)
    if not run_id_text:
        return None
    with sqlite3.connect(db_path) as conn:
        conn.row_factory = sqlite3.Row
        row = conn.execute(
            """
            SELECT
                run_id, started_at_utc, ended_at_utc, status, trigger_source, error_message,
                stats_json, progress_step, progress_pct, cancel_requested, updated_at_utc
            FROM me_refresh_runs
            WHERE run_id = ?
            """,
            (run_id_text,),
        ).fetchone()
    return dict(row) if row else None


