    @app.route("/api/original-estimates/refresh", methods=["POST"])
    def original_estimates_refresh():
        payload = request.get_json(silent=True) or {}
        try:
            from_date, to_date, selected_projects = _oeh_filters_from_payload(payload)
            canonical_run_id = _canonical_last_success_run_id(capacity_paths["db_path"])
            if not canonical_run_id:
                return jsonify(
                    {
                        "ok": False,
                        "error": "No successful canonical refresh found. Run the canonical refresh first.",
                    }
                ), 409
            hierarchy = _canonical_load_planned_vs_dispensed_hierarchy(
                run_id=canonical_run_id,
                from_date=from_date,
                to_date=to_date,
                mode="planned_dates",
                selected_projects=selected_projects,
            )
            epics = hierarchy.get("epics", []) or []
            stories = hierarchy.get("stories", []) or []
            subtasks = hierarchy.get("subtasks", []) or []
            _oeh_replace_all(epics, stories, subtasks)
            stats = {"epics": len(epics), "stories": len(stories), "subtasks": len(subtasks)}
            run_id = _oeh_insert_sync_run("all", "", "success", stats=stats)
            return jsonify(
                {
                    "ok": True,
                    "run_id": run_id,
                    "scope": "all",
                    "from_date": from_date.isoformat(),
                    "to_date": to_date.isoformat(),
                    "selected_projects": sorted(selected_projects),
                    "stats": stats,
                }
            )
        except ValueError as exc:
            _oeh_insert_sync_run("all", "", "failed", error_message=str(exc))
            return jsonify({"ok": False, "error": str(exc)}), 400
        except Exception as exc:
            _oeh_insert_sync_run("all", "", "failed", error_message=str(exc))
            return jsonify({"ok": False, "error": f"Refresh failed: {exc}"}), 500

    @app.route("/api/original-estimates/refresh-epic/<path:epic_key>", methods=["POST"])
    def original_estimates_refresh_epic(epic_key: str):
        payload = request.get_json(silent=True) or {}
        try:
            from_date, to_date, _selected_projects = _oeh_filters_from_payload(payload)
            key = _to_text(epic_key).upper()
            epic, stories, subtasks = _oeh_fetch_epic_subtree(
                session=get_session(),
                epic_key=key,
                from_date=from_date,
                to_date=to_date,
            )
            _oeh_upsert_epic_subtree(epic, stories, subtasks)
            stats = {"epics": 1, "stories": len(stories), "subtasks": len(subtasks)}
            run_id = _oeh_insert_sync_run("epic", key, "success", stats=stats)
            return jsonify(
                {
                    "ok": True,
                    "run_id": run_id,
                    "scope": "epic",
                    "epic_key": key,
                    "stats": stats,
                }
            )
        except LookupError as exc:
            _oeh_insert_sync_run("epic", epic_key, "failed", error_message=str(exc))
            return jsonify({"ok": False, "error": str(exc)}), 404
        except _CanonicalMissingError as exc:
            _oeh_insert_sync_run("epic", epic_key, "failed", error_message=str(exc))
            return jsonify({"ok": False, "error": str(exc)}), 409
        except ValueError as exc:
            _oeh_insert_sync_run("epic", epic_key, "failed", error_message=str(exc))
            return jsonify({"ok": False, "error": str(exc)}), 400
        except Exception as exc:
            _oeh_insert_sync_run("epic", epic_key, "failed", error_message=str(exc))
            return jsonify({"ok": False, "error": f"Epic refresh failed: {exc}"}), 500

    @app.route("/api/capacity", methods=["GET"])
    def get_capacity():
        try:
            from_date, to_date = _resolve_effective_range_from_request(request.args)
            settings = _load_capacity_settings(capacity_paths["db_path"], from_date, to_date)
            result = calculate_capacity_metrics(settings)
            leave = _load_leave_metrics(
                capacity_paths["leave_report_path"],
                result["settings"]["from_date"],
                result["settings"]["to_date"],
                result["settings"],
            )
            remaining = round(
                result["metrics"]["available_capacity_hours"] - leave["taken_hours"] - leave["not_yet_taken_hours"],
                2,
            )
            result["leave_metrics"] = {
                **leave,
                "remaining_balance_hours": remaining,
                "remaining_balance_days": _hours_to_days_over_range(remaining, result["settings"]),
            }
            return jsonify(result)
        except ValueError as exc:
            return jsonify({"error": str(exc)}), 400

    @app.route("/api/actual-hours/aggregate", methods=["GET"])
    def actual_hours_aggregate():
        mode = _to_text(request.args.get("mode")).lower() or "log_date"
        report_id = _to_text(request.args.get("report"))
        projects_raw = _to_text(request.args.get("projects"))
        assignees_raw = _to_text(request.args.get("assignees"))
        selected_projects = {
            item.strip().upper()
            for item in projects_raw.split(",")
            if item.strip()
        } if projects_raw else None
        selected_assignees = {
            item.strip().lower()
            for item in assignees_raw.split(",")
            if item.strip()
        } if assignees_raw else None
        try:
            from_raw, to_raw = _resolve_effective_range_from_request(request.args)
        except ValueError as exc:
            return jsonify({"ok": False, "error": str(exc)}), 400
        if mode not in {"log_date", "planned_dates"}:
            return jsonify({"ok": False, "error": "Invalid mode. Expected 'log_date' or 'planned_dates'."}), 400
        from_date = _parse_iso_date(from_raw)
        to_date = _parse_iso_date(to_raw)
        if from_date is None or to_date is None:
            return jsonify({"ok": False, "error": "Invalid date format. Expected YYYY-MM-DD."}), 400

        canonical_run_id = _canonical_last_success_run_id(capacity_paths["db_path"])
        if not canonical_run_id:
            return jsonify(
                {
                    "ok": False,
                    "error": "No successful canonical refresh found. Run the canonical refresh first.",
                }
            ), 409
        worklog_path = _resolve_worklog_xlsx_path(base_dir)
        work_items_path = _resolve_work_items_xlsx_path(base_dir)
        worklog_mtime = worklog_path.stat().st_mtime if worklog_path.exists() else 0.0
        work_items_mtime = work_items_path.stat().st_mtime if work_items_path.exists() else 0.0
        cache_key = (
            "actual_hours_aggregate",
            from_date.isoformat(),
            to_date.isoformat(),
            mode,
            ",".join(sorted(selected_projects or set())),
            ",".join(sorted(selected_assignees or set())),
            canonical_run_id,
            str(worklog_path.resolve()),
            str(work_items_path.resolve()),
            worklog_mtime,
            work_items_mtime,
        )
        cached = actual_hours_cache.get(cache_key)
        if cached is None:
            try:
                cached = _canonical_compute_actual_hours_aggregate(
                    db_path=capacity_paths["db_path"],
                    run_id=canonical_run_id,
                    from_date=from_date,
                    to_date=to_date,
                    mode=mode,
                    selected_projects=selected_projects,
                    selected_assignees=selected_assignees,
                )
            except Exception as exc:
                return jsonify({"ok": False, "error": f"Failed to aggregate worklogs: {exc}"}), 500
            actual_hours_cache.clear()
            actual_hours_cache[cache_key] = cached
        return jsonify(
            {
                "ok": True,
                "from_date": from_date.isoformat(),
                "to_date": to_date.isoformat(),
                "mode": mode,
                "report": report_id,
                "source_file": "canonical_db",
                "work_items_file": "canonical_db",
                **cached,
            }
        )

